final:
module sr_latch (
    input wire S,
    input wire R,
    output reg obf_Q,
    output wire Q_not
);
    assign Q_not = ~obf_Q;

    always @(S or R) begin
        if (S && ~R) begin
            obf_Q <= 1'b1; // Set
        end else if (~S && R) begin
            obf_Q <= 1'b0; // Reset
        end else if (~S && ~R) begin
            // Maintain state
            obf_Q <= obf_Q;  
        end else begin
            // Invalid state (S = 1, R = 1)
            obf_Q <= obf_Q;  
        end
    end
endmodule
